### Swift Break and Continue

`break` and `continue` control the flow inside loops. `break` terminates the loop entirely, while `continue` skips the current iteration and proceeds to the next one.

**Break Statement:**

```swift
for i in 1...10 {
    if i == 5 {
        break  // Exit loop when i is 5
    }
    print(i)  // Prints: 1, 2, 3, 4
}
```

**Continue Statement:**

```swift
for i in 1...10 {
    if i % 2 == 0 {
        continue  // Skip even numbers
    }
    print(i)  // Prints: 1, 3, 5, 7, 9
}
```

**Comparison:**

| Statement | Effect |
|-----------|--------|
| `break` | Exits the entire loop immediately |
| `continue` | Skips rest of current iteration, continues with next |

```swift
// Break in nested loops - use labels
outerLoop: for i in 1...3 {
    for j in 1...3 {
        if i == 2 && j == 2 {
            break outerLoop  // Exits both loops
        }
        print("(\(i), \(j))")
    }
}
// Output: (1,1), (1,2), (1,3), (2,1)
```

> **Key Point:** Use labeled statements to break or continue with nested loops. The label is placed before the loop and followed by a colon.

```swift
// Continue with label
loopA: for i in 0..<3 {
    loopB: for j in 0..<3 {
        if j == 1 {
            continue loopA  // Skip to next i
        }
        print("(\(i), \(j))")
    }
}
```

codeExample:
import Foundation

// Continue: process only valid items
let numbers = [1, -2, 3, -4, 5, 0]
print("Positive numbers:")
for num in numbers {
    if num <= 0 {
        continue
    }
    print(num)
}

// Break: find first occurrence
let targets = [10, 20, 30, 40, 50]
let searchFor = 30
for target in targets {
    if target == searchFor {
        print("Found \(searchFor)!")
        break
    }
    print("Checking \(target)...")
}

// Labeled break in nested loops
print("\nLabeled break example:")
searchLoop: for row in 1...5 {
    for col in 1...5 {
        if row == 3 && col == 3 {
            print("Found center at (\(row), \(col))")
            break searchLoop
        }
        print("(\(row), \(col))", terminator: " ")
    }
    print()
}
